dashboard.definition:
{
	"visualizations": {
		"viz_JPhveWzh": {
			"type": "splunk.pie",
			"dataSources": {
				"primary": "ds_ZkhVVEEV"
			},
			"title": "TLS Versions",
			"description": "Lookout for SSLv2, SSLv3 or TLS1.0"
		},
		"viz_abrqznRi": {
			"type": "splunk.pie",
			"dataSources": {
				"primary": "ds_qzb2NiA5"
			},
			"title": "Weak Ciphers",
			"description": "RC4-MD5 and others"
		},
		"viz_C6fcumcL": {
			"type": "splunk.markdown",
			"options": {
				"markdown": "**Use strong cryptography and security protocols over open, public networks.**\n"
			}
		}
	},
	"dataSources": {
		"ds_ZkhVVEEV": {
			"type": "ds.search",
			"options": {
				"query": "index=\"main\"\n| stats count as ccount by ssl_protocol_version\n| lookup SSL_version.csv ssl_protocol_version OUTPUT Version\n| where Version!=\"\"\n| dedup Version\n| sort -ccount\n| table Version, ccount",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Search_1"
		},
		"ds_qzb2NiA5": {
			"type": "ds.search",
			"options": {
				"query": "index=\"main\" ssl_cipher_suite_id!=\"\"\n| stats count as ccount by ssl_cipher_suite_id\n| lookup weak_ciphers.csv ssl_cipher_suite_id OUTPUT Cipher\n| where Cipher!=\"\"\n| dedup Cipher\n| sort -ccount\n| table Cipher, ccount",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"name": "Search_1 copy 1"
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"latest": "$global_time.latest$",
						"earliest": "$global_time.earliest$"
					}
				}
			},
			"ds.spl2": {
				"options": {
					"queryParameters": {
						"latest": "$global_time.latest$",
						"earliest": "$global_time.earliest$"
					}
				}
			}
		},
		"visualizations": {
			"global": {
				"showProgressBar": true
			}
		}
	},
	"inputs": {
		"input_global_trp": {
			"type": "input.timerange",
			"options": {
				"token": "global_time",
				"defaultValue": "-24h@h,now"
			},
			"title": "Global Time Range"
		}
	},
	"layout": {
		"options": {},
		"globalInputs": [
			"input_global_trp"
		],
		"tabs": {
			"items": [
				{
					"layoutId": "layout_1",
					"label": "New tab"
				}
			]
		},
		"layoutDefinitions": {
			"layout_1": {
				"type": "absolute",
				"structure": [
					{
						"item": "viz_JPhveWzh",
						"type": "block",
						"position": {
							"x": 280,
							"y": 0,
							"w": 590,
							"h": 400
						}
					},
					{
						"item": "viz_abrqznRi",
						"type": "block",
						"position": {
							"x": 870,
							"y": 0,
							"w": 570,
							"h": 400
						}
					},
					{
						"item": "viz_C6fcumcL",
						"type": "block",
						"position": {
							"x": 0,
							"y": 0,
							"w": 280,
							"h": 390
						}
					}
				],
				"options": {
					"width": 1440,
					"height": 400,
					"display": "auto"
				}
			}
		}
	},
	"description": "",
	"title": "SSL Cryptographic Details"
}
